INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('72196d367cc8a640', 'MO', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Missouri?', '["Are Missouri primaries open or closed?","Do I have to register with a party to vote in the MO primary?","How do voters choose a ballot in the Missouri primary?"]', 'Missouri utilizes an open primary system. Under RSMo 115.397, voters are not required to register with a political party prior to the election. At the polling place, voters verbally state to the election judge which party''s primary ballot they wish to vote, and they receive only that party''s ballot for the primary.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.397', 'RSMo 115.397', '2026-05-17', 'static', 'statute_citation', 'All voters and candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('8d73956cbd07a841', 'MO', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Missouri primary elections?', '["Do write-in votes count in the MO primary?","Can I run as a write-in for the Missouri primary?","Missouri primary write-in rules"]', 'No. Under RSMo 115.399, write-in votes are strictly prohibited in primary elections. To be a write-in candidate, an individual must file a declaration of intent with the Secretary of State or local election authority prior to the general election, and write-in votes are only counted in the general.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.399', 'RSMo 115.399', '2026-05-17', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('243968bdcc45e82f', 'MO', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for Missouri in 2026?', '["When do candidates file for office in Missouri?","Missouri filing deadline 2026","Last day to file to run in MO"]', 'For the 2026 election cycle, the candidate filing period for major party primary access closes at 5:00 p.m. on the last Tuesday in March (March 31, 2026). Candidates must file a declaration of candidacy and pay the required filing fee ($200 for statewide/federal, $100 for State Senate, $50 for State House) to the state or county party committee.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State - Candidate Filing', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('3a3b3e98ea8dae59', 'MO', '["federal","state"]', 'ballot_access', 'How do independent candidates access the general election ballot in Missouri?', '["Independent candidate petition threshold Missouri","Running without a party in MO","Unaffiliated candidate signature requirements Missouri"]', 'Independent candidates bypass the primary and petition directly onto the general election ballot. Under RSMo 115.321, they must submit valid signatures from registered voters equal to at least 10,000 statewide, or 2% of the total number of votes cast for the office in the last election, whichever is less.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.321', 'RSMo 115.321', '2026-05-17', 'static', 'statute_citation', 'Independent candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('12fe2d99de83e1da', 'MO', '["federal","state","county"]', 'ballot_access', 'Does Missouri have a sore loser law?', '["Can I run as an independent if I lose the MO primary?","Missouri sore loser statute","General election ballot access after primary defeat MO"]', 'Yes. Under RSMo 115.315(4), Missouri enforces a sore loser law. A person who filed as a candidate for a political party''s nomination in the primary election and lost cannot subsequently file as an independent candidate for the same or any other office in that year''s general election.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.315', 'RSMo 115.315', '2026-05-17', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('e349e58326c3ed41', 'MO', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Missouri?', '["Missouri joint ticket rules","How are Lt Gov candidates selected in MO?","Does the Governor pick a running mate in Missouri?"]', 'No. Under the Missouri Constitution (Article IV), the Governor and Lieutenant Governor are elected separately. They run in entirely separate primary and general elections, meaning it is possible for Missouri to elect a Governor and a Lieutenant Governor from two different political parties.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article IV', '2026-05-17', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('aaf378ea3f322ffe', 'MO', '["municipal","judicial"]', 'election_dates', 'When are municipal and school board elections held in Missouri?', '["Missouri April election dates","When do school boards run in MO?","Missouri spring nonpartisan elections"]', 'In Missouri, most municipal, school board, and local special district elections are held on ''General Municipal Election Day.'' This election is completely separate from the state and federal cycle and is held annually on the first Tuesday after the first Monday in April (April 7, 2026).', 'https://www.sos.mo.gov/elections/calendar', 'Missouri Secretary of State - Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'Local candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('a14c3e9dcce15353', 'MO', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Missouri for 2026?', '["Missouri primary date 2026","When is Election Day 2026 in Missouri?","August primary Missouri"]', 'The Missouri state and federal primary election will be held on Tuesday, August 4, 2026. The general election will be held on Tuesday, November 3, 2026. Polls are open from 6:00 a.m. to 7:00 p.m.', 'https://www.sos.mo.gov/elections/calendar', 'Missouri Secretary of State - Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('a3a73abfa9cf2cde', 'MO', '["state"]', 'election_dates', 'Is Governor Mike Kehoe running for re-election in 2026?', '["Missouri Governor election 2026","Who is defending the MO Governor seat?","Is Mike Kehoe on the 2026 ballot?"]', 'No. Missouri elects its Governor strictly on the presidential election cycle. Governor Mike Kehoe (R) was elected in 2024 and his four-year term runs through early 2029. There is no gubernatorial race on the 2026 midterm ballot.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('a942d5eb23c4df3c', 'MO', '["federal"]', 'election_dates', 'Which U.S. Senate seats are up for election in Missouri in 2026?', '["Is Eric Schmitt up for re-election in 2026?","When is Josh Hawley''s next election?","Missouri US Senate cycle 2026"]', 'The Class 3 U.S. Senate seat held by Eric Schmitt (R) is up for election in 2026. Senator Josh Hawley (Class 1) was recently re-elected in 2024 and is not on the ballot again until 2030.', 'https://www.senate.gov/senators/Class_III.htm', 'U.S. Senate - Class III Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('472a3fbd21883719', 'MO', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Missouri in 2026?', '["Is the Attorney General up in 2026?","MO statewide election list 2026","When is the State Auditor election in MO?"]', 'The State Auditor (currently Scott Fitzpatrick) is the ONLY statewide executive office on the 2026 midterm ballot in Missouri. The Governor, Lieutenant Governor, Secretary of State, Attorney General, and State Treasurer are all elected during presidential election years and will not appear on the ballot again until 2028.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State - Candidate Filing', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('85dc2c5437439a91', 'MO', '["federal"]', 'election_dates', 'Will the 2026 Missouri U.S. House races use a new mid-decade redistricting map?', '["Missouri mid-decade congressional redistricting 2025","Are there pending redistricting lawsuits in Missouri?","Status of Missouri 5th Congressional District 2026"]', 'This is currently a highly volatile issue. The legislature enacted a new mid-decade congressional map in a 2025 special session aimed at eliminating the safe Democratic 5th District. The Missouri Supreme Court upheld the map in March 2026. However, the ''People Not Politicians'' coalition has submitted referendum signatures to suspend the map. If certified by the Secretary of State, the 2026 races will revert to the post-2020 census maps while voters decide the new map''s fate.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State - Petitions', '2026-05-17', 'volatile', 'official_source_direct', 'Federal candidates and Strategists', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('07cef40df11ba03f', 'MO', '["state"]', 'election_dates', 'Which Missouri State Legislature seats are up for election in 2026?', '["Are all Missouri House seats up in 2026?","Missouri Senate election cycle 2026","Which legislative districts are on the ballot in MO?"]', 'All 163 seats in the Missouri House of Representatives (2-year terms) are up for election in 2026. In the Missouri Senate (34 members, 4-year staggered terms), the 17 even-numbered districts are on the 2026 ballot.', 'https://www.senate.mo.gov/', 'Missouri State Senate', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('302a8e29546c001d', 'MO', '["judicial"]', 'election_dates', 'Are Missouri Supreme Court seats on the 2026 ballot?', '["Missouri Plan judicial retention elections","How are judges selected in Missouri?","Do MO Supreme Court judges run in the primary?"]', 'Missouri Supreme Court and appellate judges do not run in competitive elections. Under the ''Missouri Nonpartisan Court Plan,'' they are appointed by the Governor from a judicial commission''s list. After serving one year, they face a nonpartisan retention election at the next general election, and subsequently every 12 years.', 'https://www.courts.mo.gov/page.jsp?id=297', 'Missouri State Courts - Nonpartisan Court Plan', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('72818c77d8bc42fe', 'MO', '["state"]', 'election_dates', 'What is the schedule for the Missouri State Legislature''s sessions?', '["When does the MO legislature meet?","Missouri May 30 legislative session deadline","Is the Missouri legislature full time?"]', 'The Missouri General Assembly is a part-time legislature. Under Article III, Section 20(a) of the Missouri Constitution, the regular session convenes annually on the first Wednesday after the first Monday in January and must constitutionally adjourn by 6:00 p.m. on May 30.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article III, Section 20(a)', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('1349c6e0ce666d4e', 'MO', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Missouri?', '["Age and residency for Missouri Governor","Missouri Constitution Article IV Section 3 qualifications","Who can be Governor of MO?"]', 'Under Article IV, Section 3 of the Missouri Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States for at least 15 years, and a resident of Missouri for at least 10 years preceding the election.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article IV, Section 3', '2026-05-17', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('55c09a71f5178bdc', 'MO', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Missouri?', '["Missouri Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in MO?","Qualifications for Lieutenant Governor of Missouri"]', 'Under Article IV, Section 10 of the Missouri Constitution, the qualifications for Lieutenant Governor are identical to those for Governor. A candidate must be at least 30 years old, a U.S. citizen for 15 years, and a Missouri resident for 10 years.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article IV, Section 10', '2026-05-17', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('bd13299bad7598e5', 'MO', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Missouri State Legislature?', '["Qualifications for MO State Representative","Age requirement Missouri State Senate","Do I have to live in my district to run in MO?"]', 'Under Article III of the Missouri Constitution, State House candidates must be 24 years old, a registered voter for 2 years, and a district resident for 1 year. State Senate candidates must be 30 years old, a registered voter for 3 years, and a district resident for 1 year prior to the election.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article III', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('f712a5493e201ffe', 'MO', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Missouri?', '["US Senate residency requirements Missouri","Age to run for Congress in Missouri","Federal constitutional requirements for MO candidates"]', 'Federal candidates must meet U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected. District residency is not required for the House.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State - Candidate FAQ', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('de4ddf3ae04f3048', 'MO', '["state"]', 'candidate_eligibility', 'Does the Missouri Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in MO","Do I need to be a member of the bar to be MO AG?","Legal requirements for Missouri Attorney General"]', 'Yes. While the Missouri Constitution outlines broad executive qualifications, statutory law mandates that the Attorney General be an attorney authorized and licensed to practice law in the Supreme Court of Missouri.', 'https://ago.mo.gov/', 'Missouri Attorney General''s Office', '2026-05-17', 'static', 'secondary_source', 'Statewide candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('bb1cdfab0d719643', 'MO', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Missouri?', '["Missouri county commissioner qualifications","Can I run for county board in MO?","County residency for MO officials"]', 'To run for a county office (such as County Commissioner), a candidate must generally be a registered voter and a resident of the county (and the specific district, if applicable) for at least one year immediately preceding the date of the election.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State - Local Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('4596b71f1bcf3d9b', 'MO', '["state"]', 'candidate_eligibility', 'What are the term limits for Missouri executive and legislative offices?', '["8-year term limit Missouri","How long can I serve in the Missouri House?","Can a term-limited MO senator run for Governor?"]', 'Missouri enforces strict term limits. The Governor and State Treasurer are limited to two four-year terms. State legislators are limited to 8 years in the State House and 8 years in the State Senate, for a lifetime maximum of 16 legislative years (Article III, Section 8 of the Missouri Constitution).', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article III, Section 8', '2026-05-17', 'static', 'statute_citation', 'State executive and legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('127302d93136d9d2', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Missouri?', '["Missouri voter ID requirements","Do I need my driver''s license to vote in MO?","HB 1878 photo ID Missouri Supreme Court"]', 'Yes. Under HB 1878, Missouri requires voters to present a non-expired, government-issued photo ID (such as a Missouri driver''s license, non-driver ID, passport, or military ID) to cast a regular ballot. The Missouri Supreme Court upheld the constitutionality of this strict photo ID requirement in March 2026.', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('0a3ef88f28838587', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Missouri a universal mail ballot state?', '["Do all voters get a mail ballot in Missouri?","Missouri vote-by-mail system","Are there traditional polling places in MO?"]', 'No. Missouri is not a universal mail ballot state. Traditional in-person voting on Election Day is the primary method of casting a ballot. Mail-in absentee ballots are restricted and generally require a valid excuse (e.g., absence from jurisdiction, illness, physical disability).', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State - How to Vote', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('e81d78306d6523ea', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Missouri offer early in-person voting?', '["Can I vote early in person in MO?","Missouri no-excuse in-person absentee voting","Two weeks early voting Missouri"]', 'Yes. While traditional mail-in voting requires an excuse, Missouri offers two weeks of ''no-excuse in-person absentee voting'' leading up to Election Day. During this period, any registered voter may go to designated local election authority locations to cast their ballot early, provided they show a valid government-issued photo ID.', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('58cde38c9ebfd6d5', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Missouri offer same-day registration?', '["Last day to register to vote in MO","Missouri same day voter registration","Voter registration deadline 2026 Missouri"]', 'The deadline to register to vote in Missouri is 27 days before an election (RSMo 115.135). Missouri DOES NOT offer same-day voter registration. Residents must be fully registered prior to the deadline to participate in either the early voting period or on Election Day.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.135', 'RSMo 115.135', '2026-05-17', 'static', 'statute_citation', 'Voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('b8c58d1f362bd552', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Missouri?', '["How close can I campaign to a polling place in MO?","Missouri 25 feet electioneering rule","MO buffer zone around voting centers"]', 'Under RSMo 115.637, Missouri enforces an electioneering buffer zone of 25 feet from the outer door of a polling place, or any interior area of the building where voting is taking place. Distributing campaign literature or displaying campaign signs inside this zone is prohibited.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.637', 'RSMo 115.637', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('87559e6437a1da0f', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Missouri?', '["Can felons vote in Missouri state?","Felony voting rights restoration MO","Voting on parole in Missouri"]', 'In Missouri, individuals convicted of a felony lose their voting rights while incarcerated AND while on probation or parole. Voting rights are automatically restored only after the individual has fully completed their entire sentence, including all periods of probation and parole (RSMo 115.133). Once completed, they must re-register to vote.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.133', 'RSMo 115.133', '2026-05-17', 'static', 'statute_citation', 'Voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('fcbde5642f5640fc', 'MO', '["county"]', 'voter_interaction', 'How is election administration structured across Missouri counties?', '["Missouri county election administration","How many county clerks in MO?","Local election control Missouri St. Louis"]', 'Election administration is highly decentralized in Missouri. Campaigns must coordinate with 116 local election authorities. This includes 114 county clerks (or local election boards), the independent City of St. Louis, and Kansas City (which operates its own independent election board separate from Jackson County).', 'https://www.sos.mo.gov/elections/goVoteMissouri/localelectionauthority', 'Missouri Secretary of State - Local Election Authorities', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('6088ec10a2a8d606', 'MO', '["state","county"]', 'finance_ethics', 'What are the campaign contribution limits in Missouri for the 2026 cycle?', '["Are there contribution limits in Missouri?","MO individual donation caps 2026 election","Federal court ruling Missouri campaign finance"]', 'Despite some legal challenges to PAC limits, direct candidate contribution limits absolutely EXIST in Missouri under Article VIII, Section 23 of the state Constitution. For the 2025-2026 cycle (indexed for inflation), individuals and PACs are limited to contributing approximately $2,825 to statewide candidates, $1,125 to State Senate candidates, and $375 to State House candidates per election.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('1c6640ff2e60696b', 'MO', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Missouri campaigns?', '["Corporate contribution ban Missouri state","Can a business donate to my campaign in MO?","Corporate campaign finance rules Missouri"]', 'No. Direct corporate and labor union contributions to candidate committees are strictly PROHIBITED in Missouri under Article VIII, Section 23.3(3)(a) of the Missouri Constitution. Corporations and unions may only establish a separate Political Action Committee (PAC) to make political contributions.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article VIII', '2026-05-17', 'static', 'statute_citation', 'Candidates and Businesses', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('f35638943a6b5fb1', 'MO', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Missouri?', '["Where do I file campaign finance reports in MO?","What is the Missouri Ethics Commission?","Does the MO Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in Missouri are administered by the Missouri Ethics Commission (MEC), not the Secretary of State. All state and local candidates must register their committees and file their contribution and expenditure reports electronically through the MEC portal.', 'https://mec.mo.gov/', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('eee8b3c72e652cf0', 'MO', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Missouri candidates?', '["MEC filing dates 2026","When are campaign finance reports due in MO?","Missouri pre-primary and pre-general report deadlines"]', 'Active candidate committees must file quarterly reports (January 15, April 15, July 15, October 15). Additionally, leading up to an election, candidates must file an ''8-Day Before'' report and a ''30-Day After'' report for both the primary and general elections.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Deadlines.aspx', 'Missouri Ethics Commission - Reporting Deadlines', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('aa60e2ece7128da5', 'MO', '["state","county","municipal"]', 'finance_ethics', 'What are Missouri''s rapid disclosure requirements for late contributions?', '["Missouri 48-hour large contribution report","Late contribution reporting Missouri MEC","When do I file a rapid report in MO?"]', 'Any contribution from a single source exceeding $5,000 must be reported electronically within 48 hours of receipt at any time during the year. Furthermore, any contribution over $250 received within 11 days of an election must be reported within 24 hours.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Deadlines.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('28ba657b27b99c6d', 'MO', '["state"]', 'finance_ethics', 'Does Missouri provide public financing for state campaigns?', '["Public matching funds for Missouri Governor","State funded campaigns Missouri status","Government campaign grants MO"]', 'No. Missouri does not have a system of public financing or matching funds for state-level political campaigns. Candidates must rely entirely on private contributions within the statutory limits.', 'https://mec.mo.gov/', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('0fc3388ba38cac69', 'MO', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Missouri?', '["MO personal use prohibition campaign finance","Can I use campaign money for personal items in MO?","Prohibited expenditures Missouri MEC"]', 'Yes. Under RSMo 130.034, campaign contributions cannot be converted to personal use. They must be strictly used for campaign expenses, ordinary expenses incurred relating to the duties of public office, or returned to donors.', 'https://revisor.mo.gov/main/OneSection.aspx?section=130.034', 'RSMo 130.034', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('4487a92aa7b4620a', 'MO', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Missouri legislators?', '["Can Missouri legislators raise money during session?","Lobbyist contribution ban MO legislature","Legislative session contribution rules Missouri"]', 'No. Unlike some states, Missouri does not have a statutory ''session freeze'' that prohibits legislators from accepting campaign contributions while the General Assembly is in regular session. However, strict lobbyist gift limits (banning non-campaign gifts over $5) remain in effect year-round.', 'https://mec.mo.gov/', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('986a979249825e76', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Missouri voter registration list?', '["Missouri voter file cost","How to get the voter list in MO","MO registered voter database access"]', 'Campaigns and political committees can purchase the statewide voter registration list directly from the Missouri Secretary of State or specific county files from local election authorities. The file includes voter names, addresses, and voting history (which elections they participated in, though not who they voted for). It requires submitting a formal request form with a fee, and Missouri law strictly restricts the use of this data to political and election-related purposes.', 'https://www.sos.mo.gov/elections/VoterFile/', 'Missouri Secretary of State - Voter File Request', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('74dceecd363953ee', 'MO', '["federal"]', 'redistricting', 'Who draws Missouri''s congressional maps?', '["Does the MO legislature draw US House maps?","Who has the authority to draw congressional district lines in Missouri?","Missouri congressional redistricting process"]', 'In Missouri, congressional districts are drawn by the state legislature and must be signed by the Governor (subject to standard veto overrides). For the 2026 cycle, this process is highly volatile, as a mid-decade map passed by the legislature in 2025 is currently being challenged by a citizen veto referendum.', 'https://ballotpedia.org/Redistricting_in_Missouri', 'Ballotpedia - Redistricting in Missouri', '2026-05-17', 'volatile', 'secondary_source', 'Federal candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('a7b3e6ca56cd4e4e', 'MO', '["federal"]', 'redistricting', 'What are the legal criteria for congressional redistricting in Missouri?', '["Standards for drawing Missouri congressional lines","Missouri gerrymandering rules US House","Congressional map requirements MO"]', 'Under the U.S. and Missouri Constitutions, congressional districts must have nearly equal populations (strict equality) and must comply with the Voting Rights Act to not discriminate on the basis of race. Districts must also be contiguous and as compact as may be.', 'https://ballotpedia.org/Redistricting_in_Missouri', 'Ballotpedia - Redistricting in Missouri', '2026-05-17', 'static', 'secondary_source', 'Federal candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('d5740bcbf3a58050', 'MO', '["state"]', 'redistricting', 'Who draws Missouri State Senate districts?', '["Missouri Judicial Redistricting Commission","Who redistricts the MO Senate?","State Senate map process Missouri"]', 'Missouri State Senate districts are initially assigned to a bipartisan Nonpartisan Senate Apportionment Commission. If that commission deadlocks and fails to approve a map, the responsibility falls to the Judicial Redistricting Commission (composed of six appellate judges appointed by the Missouri Supreme Court). The Judicial Redistricting Commission drew the current State Senate maps.', 'https://budplan.oa.mo.gov/redistricting-office/judicial-commission', 'Missouri Office of Administration - Judicial Redistricting Commission', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('dc326e85483599b5', 'MO', '["state"]', 'redistricting', 'Who draws Missouri State House districts?', '["Missouri House redistricting commission","Independent Bipartisan Citizens Commission MO","Who redistricts the State House in Missouri?"]', 'The Missouri House of Representatives districts are drawn by the Independent Bipartisan Citizens Commission. This politically balanced commission is appointed by the Governor from lists submitted by the major political parties. They unanimously approved the current State House map.', 'https://ballotpedia.org/Redistricting_in_Missouri', 'Ballotpedia - Redistricting in Missouri', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('e894d284a65b806d', 'MO', '["state"]', 'redistricting', 'Are the current Missouri state legislative maps operative for the 2026 cycle?', '["Status of 2022 Missouri redistricting maps","Are there pending legislative redistricting lawsuits in Missouri?","Missouri 2026 state legislative boundaries"]', 'Yes. The state legislative maps approved in early 2022 (by the Independent Bipartisan Citizens Commission for the House, and the Judicial Redistricting Commission for the Senate) remain fully operative for the 2026 election cycle and face no systemic legal challenges.', 'https://budplan.oa.mo.gov/redistricting-office/senate-maps', 'Missouri Office of Administration', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('b7414a24d4bfaa21', 'MO', '["state"]', 'recall_rules', 'Does Missouri have a recall mechanism for state officials?', '["Can the Governor of Missouri be recalled?","How to recall a state senator in MO","Statewide recall election rules Missouri"]', 'No. The State of Missouri does not have any constitutional or statutory provision allowing for the recall of state-level elected officials, including the Governor, statewide executives, or state legislators.', 'https://ballotpedia.org/Laws_governing_recall_in_Missouri', 'Laws governing recall in Missouri', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('900bbb6510b9caca', 'MO', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Missouri?', '["Missouri county commissioner recall rules","Signature requirement local recall Missouri","Recalling a mayor in MO"]', 'While state officials cannot be recalled, Missouri law allows for the recall of local elected officials in certain jurisdictions, such as third-class counties and municipalities with specific charters. The signature threshold and procedures vary significantly based on the specific local municipal or county charter.', 'https://ballotpedia.org/Laws_governing_recall_in_Missouri', 'Laws governing recall in Missouri', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('36038c7e5604d53d', 'MO', '["state"]', 'ballot_access', 'What is the signature threshold for a constitutional amendment by initiative in Missouri?', '["How to amend the MO constitution by initiative","Missouri citizen initiative signature requirements","Geographic distribution rule for MO constitutional initiatives"]', 'To qualify a constitutional amendment initiative for the ballot, proponents must gather valid signatures equal to at least 8% of the total votes cast for Governor in the previous gubernatorial election. Crucially, this 8% threshold must be met in at least six of Missouri''s eight congressional districts.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State - Petitions', '2026-05-17', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('d386aef1a3db4e29', 'MO', '["state"]', 'ballot_access', 'What is the signature threshold for a statutory initiative in Missouri?', '["How to pass a state law by initiative in MO","Missouri statutory initiative signature count","Difference between constitutional and statutory initiative Missouri"]', 'To qualify a statutory (state law) initiative for the ballot, proponents must gather valid signatures equal to at least 5% of the total votes cast for Governor in the previous gubernatorial election. Like constitutional amendments, this 5% threshold must be met in at least six of Missouri''s eight congressional districts.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State - Petitions', '2026-05-17', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('a1bb78641eafb707', 'MO', '["state"]', 'ballot_access', 'What is the threshold and deadline for a veto referendum in Missouri?', '["How to refer a MO bill to the ballot","Missouri citizen referendum rules","Veto referendum signature threshold Missouri state"]', 'Citizens can refer a passed legislative act to the ballot via a veto referendum. This requires signatures equal to 5% of the votes cast for Governor in the previous election, gathered in at least six of the eight congressional districts. Signatures must be submitted within 90 days following the final adjournment of the legislative session.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State - Petitions', '2026-05-17', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('5235bef30073c299', 'MO', '["state"]', 'ballot_access', 'What are the highly volatile ballot initiatives in Missouri for 2026?', '["Respect Missouri Voters initiative 2026","Missouri congressional map referendum","Major ballot measures Missouri 2026"]', 'The 2026 cycle in Missouri features highly volatile citizen-led ballot items: 1) A veto referendum on the mid-decade congressional redistricting map, which suspends the map if certified. 2) The ''Respect Missouri Voters'' initiative, which would require an 80% supermajority in the legislature to amend or repeal any law previously approved by voters via the initiative process.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State - 2026 Petitions', '2026-05-17', 'volatile', 'official_source_direct', 'Ballot measure committees and Strategists', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('620c37a7583854af', 'MO', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Missouri?', '["Missouri ballot measure pass threshold","Does a measure need a supermajority in MO?","Majority vote requirements Missouri ballot measures"]', 'In Missouri, all citizen initiatives (both statutory and constitutional) and legislatively referred constitutional amendments require only a simple majority (over 50%) of the total votes cast on that specific measure to pass.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T15-55-57_missouri_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('fe335a1aa7352708', 'MO', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Missouri?', '["Requirements to run for MO Secretary of State","Who can run for Secretary of State in MO?","Residency rules for Missouri SOS"]', 'Under the Missouri Constitution and state statutes, a candidate for Secretary of State must be a citizen of the United States, a registered voter, and a resident of the state of Missouri for at least one year immediately preceding their election.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State - Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('77ba6460b910ec84', 'MO', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Missouri?', '["Eligibility for Missouri State Treasurer","Who can run for State Treasurer in MO?","Missouri Treasurer residency requirements"]', 'Under Article IV, Section 19 of the Missouri Constitution, a candidate for State Treasurer must be a citizen of the United States and a resident of Missouri for at least one year immediately preceding the election.', 'https://www.sos.mo.gov/CMSImages/Publications/CurrentMissouriConstitution.pdf', 'Missouri Constitution Article IV, Section 19', '2026-05-17', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('252370ff31832350', 'MO', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Missouri?', '["Run for school board Missouri requirements","Who can be a school board member in MO?","School board age rules Missouri"]', 'To run for a local school board in Missouri, a candidate must be a citizen of the United States, at least 24 years old, a resident taxpayer of the school district, and must have resided in the state for at least one year preceding the election.', 'https://www.sos.mo.gov/elections/candidates', 'Missouri Secretary of State - Local Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('104946bad250764c', 'MO', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Missouri Supreme Court justices?', '["Missouri Supreme Court Justice eligibility","Years of practice required for MO Supreme Court","Missouri Plan judicial requirements"]', 'Under the ''Missouri Plan'' for merit selection, Supreme Court justices must be at least 30 years old, a U.S. citizen for at least 15 years, a qualified voter of the state for at least nine years, and must be an attorney licensed to practice law in Missouri.', 'https://www.courts.mo.gov/page.jsp?id=297', 'Missouri State Courts', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('b542389064477c94', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in Missouri?', '["How to fix a rejected signature in MO","Missouri ballot cure process deadline","Missing notary on MO mail ballot"]', 'Missouri law is strict regarding absentee ballots. Ballots must be properly signed and, in most cases, notarized. If a signature or notary stamp is missing, the election authority is generally required to reject the ballot. While some local election authorities may attempt to notify voters of a defect, there is no standardized, statewide statutory cure period allowing voters to fix ballot envelope errors after Election Day.', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('538bab959143d152', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Missouri?', '["When are military ballots due in Missouri?","UOCAVA return deadline MO","Overseas voting rules Missouri state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters 45 days before an election. Voted ballots must be received by the local election authority by 7:00 p.m. on Election Day to be counted. Military personnel in hostile fire zones may return their ballots via a secure electronic portal.', 'https://www.sos.mo.gov/elections/goVoteMissouri/registermilitary', 'Missouri Secretary of State - Military/Overseas', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('226660a2ee915d8c', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Missouri?', '["What is a provisional ballot in MO?","Voting without ID Missouri","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued in Missouri when a voter claims to be registered but their name does not appear on the polling place roster, or if the voter fails to present a valid government-issued photo ID. If issued for lack of ID, the ballot counts if the voter returns with a valid ID before polls close, or if the signature matches the voter registration record.', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State - Provisional Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('e8b3a3581371698e', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Missouri have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Missouri DMV?","MO motor voter automatic registration","Do I have to register to vote if I get a MO driver''s license?"]', 'No. Missouri does not have Automatic Voter Registration (AVR). While the Department of Revenue (DMV) offers eligible citizens the opportunity to register to vote when applying for a license—in compliance with federal Motor Voter laws—voters must actively opt-in and complete the registration process.', 'https://www.sos.mo.gov/elections/goVoteMissouri/register', 'Missouri Secretary of State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('03bfe5b0c2e68e92', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Missouri offer Online Voter Registration?', '["Can I register to vote online in MO?","Missouri electronic voter registration","MO SOS online registration portal"]', 'Yes. Eligible Missouri residents can register to vote or update their registration electronically via the Secretary of State''s online portal. To submit the registration entirely online, the applicant must provide the last four digits of their Social Security number and a touchscreen signature.', 'https://s1.sos.mo.gov/elections/voterregistration/', 'Missouri Secretary of State - Online Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('fddb342f5b829805', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Missouri maintain its voter registration lists?', '["MO voter list maintenance rules","How are inactive voters handled in Missouri?","Missouri voter roll cleaning process"]', 'Local election authorities in Missouri conduct list maintenance primarily using the National Change of Address (NCOA) system. Voters whose mail is returned undeliverable are sent a forwardable canvass notice; if they fail to respond and do not vote in two consecutive federal general elections, their registration is canceled.', 'https://www.sos.mo.gov/elections/goVoteMissouri/register', 'Missouri Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('fec10d8b39d0c901', 'MO', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in Missouri?', '["When is the last day to mail my ballot in MO?","Missouri mail ballot postmark deadline","What time are ballots due in Missouri?"]', 'In Missouri, completed absentee ballots must be physically RECEIVED by the local election authority by 7:00 p.m. on Election Day. Missouri does not have a postmark grace period; ballots arriving after 7:00 p.m. on Election Day are rejected, regardless of when they were mailed.', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('43f57a8403bdee79', 'MO', '["federal","state","county"]', 'runoff_rules', 'Does Missouri use runoff elections for close races?', '["Are there runoffs in Missouri primaries?","How are tied elections decided in Missouri?","Tie-breaker rules Missouri elections"]', 'No. Missouri does not hold runoff elections for state or federal offices; plurality determines the winner. Under RSMo 115.517, in the event of an exact tie for state or federal office, the Governor calls a special election. Alternatively, if both tied candidates officially agree, the race may be decided by drawing lots.', 'https://revisor.mo.gov/main/OneSection.aspx?section=115.517', 'RSMo 115.517', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('fab4c368f4ab5815', 'MO', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Missouri?', '["Does Missouri use ranked choice voting?","RCV status in Missouri 2026","Instant runoff voting MO"]', 'No. Ranked Choice Voting (RCV) is strictly prohibited across the state. In 2024, Missouri voters approved Constitutional Amendment 7, which explicitly banned the use of Ranked Choice Voting for all local, state, and federal elections, with a grandfather clause solely for St. Louis City''s pre-existing nonpartisan approval voting system.', 'https://www.sos.mo.gov/elections/petitions', 'Missouri Secretary of State - Amendment 7 (2024)', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('f18d4407e129eea1', 'MO', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Missouri campaign materials?', '["Missouri ''Paid for by'' rules","Campaign ad disclaimer requirements MO","Political taglines Missouri MEC"]', 'Under Missouri campaign finance law, all printed matter and broadcast ads must feature a clear ''Paid for by'' disclaimer followed by the name of the candidate committee, PAC, or individual funding the communication. For committees, the name of the designated treasurer must also be included in the disclaimer.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission - Disclaimers', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('934dec6c8b6af882', 'MO', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Missouri?', '["MO campaign coordination rules","When is a PAC expenditure not independent in Missouri?","Prohibition on candidate-PAC coordination MO"]', 'An expenditure is ''coordinated'' (and thus treated as an in-kind contribution subject to statutory contribution limits) if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. The MEC strictly defines independence to ensure PACs do not bypass candidate limits.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('a62fd6cd4db2d5f2', 'MO', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Missouri?', '["MO MEC late fee","Penalty for missing a Missouri campaign finance deadline","Ethics Commission fine for late filing MO"]', 'The Missouri Ethics Commission (MEC) assesses mandatory late fees for missing disclosure deadlines. Under RSMo 105.963, late fees accrue daily ($10/day for the first 30 days, then $100/day thereafter) up to a maximum of $3,000 per report.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('ddab2e4ce70d4695', 'MO', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Missouri campaign committee terminate?', '["Closing a Missouri campaign committee","MEC committee termination requirements","Final campaign finance report Missouri"]', 'A candidate committee may formally terminate its registration with the MEC only when it has achieved a zero cash balance, disposed of all surplus funds legally, and resolved all outstanding debts or loans. A formal Termination Report must be filed marking the committee as closed.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('ba20671f3d1b99de', 'MO', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Missouri?', '["MO independent expenditure reporting MEC","Disclosure for MO independent expenditure groups","Reporting thresholds for outside spending Missouri"]', 'Committees making independent expenditures must report them on standard MEC filing schedules. However, any entity (including non-committees) making independent expenditures aggregating more than $500 must file a Non-Committee Expenditure Report within 14 days of exceeding the threshold.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('0ad183734cf3b339', 'MO', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Missouri?', '["Missouri in-kind contribution valuation rules","Reporting non-monetary donations Missouri campaign","Fair market value for in-kind gifts MO"]', 'In-kind contributions (donated goods, services, or equipment) must be reported to the MEC at their fair market value. They are reported simultaneously as both a contribution receipt and an expenditure, and they count directly toward the donor''s per-election contribution limit.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('eeaf8b52253235b6', 'MO', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Missouri?', '["Missouri candidate personal loan limits","Can I pay myself back for a campaign loan in MO?","Reporting candidate loans in MEC"]', 'A candidate may loan an unlimited amount of their own personal funds to their candidate committee. Unlike contributions from third parties, candidate personal funds are not subject to any contribution limits. These must be reported as loans and may be repaid from campaign funds.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('ac194d6651d38e6d', 'MO', '["state","county","municipal"]', 'finance_ethics', 'What can Missouri candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in MO?","MO surplus campaign funds rules","Donating remaining campaign funds Missouri"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain the funds for a future campaign, return them pro-rata to contributors, transfer them to a political party, or donate them to an IRS-recognized charitable organization.', 'https://revisor.mo.gov/main/OneSection.aspx?section=130.034', 'RSMo 130.034', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('5bb0099cd82f9cdb', 'MO', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Missouri?', '["MO PAC donation limits to candidates 2026","Political committee vs individual contribution limit Missouri","Maximum PAC gift to state legislator MO"]', 'In Missouri, Political Action Committees (PACs) are subject to the exact same contribution limits as individuals when donating directly to a candidate committee. For the 2025-2026 cycle, PACs are limited to contributing ~$2,825 to statewide candidates, ~$1,125 to State Senate candidates, and ~$375 to State House candidates per election.', 'https://mec.mo.gov/MEC/Campaign_Finance/CF_Info.aspx', 'Missouri Ethics Commission - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'State and County candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('85db5cd4e3e23db2', 'MO', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Missouri?', '["When are county sheriffs elected in MO?","Missouri county official term lengths","Are county assessors on the 2026 ballot?"]', 'Elected county officials in Missouri—including Sheriffs, Assessors, Clerks, and Treasurers—generally serve four-year terms. They are elected on a partisan basis and are split between midterm and presidential election cycles, meaning specific county seats will be highly contested on the 2026 ballot.', 'https://www.sos.mo.gov/elections/calendar', 'Missouri Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('e7d017d327b3433f', 'MO', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Missouri elections?', '["When are Missouri election results official?","MO certification deadline","State Board of Canvassers meeting Missouri"]', 'Local election authorities must complete their canvass and certify local results no later than the second Tuesday following the election. The state Board of Canvassers must meet to officially certify statewide and federal election results no later than the second Tuesday in December.', 'https://www.sos.mo.gov/elections/goVoteMissouri/howtovote', 'Missouri Secretary of State - Canvass', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T15-55-57_missouri_full_v1'),
  ('889b4e7791906743', 'MO', '["federal","state"]', 'election_dates', 'When and how are special elections called in Missouri?', '["Missouri special election timeline","Who calls a special election to fill a US House vacancy in MO?","Filling a midterm vacancy Missouri"]', 'Special elections to fill federal or state legislative vacancies are called by a writ of election from the Governor. Under state law, the special election must be held on one of the state''s statutorily authorized municipal or general election dates to minimize unbudgeted costs.', 'https://www.sos.mo.gov/elections/calendar', 'Missouri Secretary of State - Special Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T15-55-57_missouri_full_v1')
